import { Component, Inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { MAT_DIALOG_DATA, MatDialogModule, MatDialogRef } from '@angular/material/dialog';
import { MatButtonModule } from '@angular/material/button';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatSelectModule } from '@angular/material/select';
import { MatDatepickerModule } from '@angular/material/datepicker';
import { MatNativeDateModule, MAT_DATE_FORMATS, MAT_DATE_LOCALE } from '@angular/material/core';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatIconModule } from '@angular/material/icon';
import { MatCheckboxModule } from '@angular/material/checkbox';

import { RoomsService, Habitacion } from '../../services/rooms.service';
import { UsersService, UsuarioMini } from '../../services/users.service';
import { ReservationsService } from '../../services/reservations.service';
import { UsuarioLogueado } from '../../services/auth.service';

export interface ReservationCreateDialogData {
  room?: Habitacion;
  guest?: UsuarioLogueado;
}

type EstadoReserva = 0 | 1 | 2 | 3 | 4 | 5;

@Component({
  standalone: true,
  selector: 'app-reservation-create-dialog',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    MatDialogModule,
    MatButtonModule,
    MatFormFieldModule,
    MatInputModule,
    MatSelectModule,
    MatDatepickerModule,
    MatNativeDateModule,
    MatProgressSpinnerModule,
    MatIconModule,
    MatCheckboxModule,
  ],
  providers: [
    // Mostrar fechas en el input con el formato requerido por el proyecto.
    { provide: MAT_DATE_LOCALE, useValue: 'es-ES' },
    {
      provide: MAT_DATE_FORMATS,
      useValue: {
        parse: {
          dateInput: 'dd/MM/yyyy',
        },
        display: {
          dateInput: 'dd/MM/yyyy',
          monthYearLabel: 'MMM yyyy',
          dateA11y: 'dd/MM/yyyy',
          monthYearA11y: 'MMMM yyyy',
        },
      },
    },
  ],
  templateUrl: './reservation-create-dialog.component.html',
  styleUrl: './reservation-create-dialog.component.scss',
})
export class ReservationCreateDialogComponent {
  loading = false;
  errorMessage = '';

  rooms: Habitacion[] = [];
  users: UsuarioMini[] = [];

  /** Cuando es true, habitación y huésped vienen predefinidos (vista invitado) y se muestran bloqueados. */
  lockGuestAndRoom = false;

  // Mapeo igual al enum ReservationStatus del backend.
  estados: { value: EstadoReserva; label: string }[] = [
    { value: 0, label: 'Pendiente' },
    { value: 1, label: 'Confirmado' },
    { value: 2, label: 'En proceso' },
    { value: 3, label: 'Completado' },
    { value: 4, label: 'Cancelado' },
    { value: 5, label: 'Ausente' },
  ];

  form: FormGroup;

  constructor(
    private fb: FormBuilder,
    private dialogRef: MatDialogRef<ReservationCreateDialogComponent>,
    @Inject(MAT_DIALOG_DATA) public data: ReservationCreateDialogData | unknown,
    private roomsService: RoomsService,
    private usersService: UsersService,
    private reservationsService: ReservationsService
  ) {
    const today = new Date();
    const entradaDefault = this.startOfDay(today);
    const salidaDefault = this.endOfDay(today);

    this.form = this.fb.group({
      idReservacion: [''],
      idHabitacion: ['', [Validators.required]],
      idHuesped: ['', [Validators.required]],
      fechaEntrada: [entradaDefault, [Validators.required]],
      fechaSalida: [salidaDefault, [Validators.required]],
      estado: [0 as EstadoReserva, [Validators.required]],
      numeroHuespedes: [1, [Validators.required, Validators.min(1)]],
      montoTotal: [0, [Validators.required, Validators.min(0)]],
      moneda: ['HNL', [Validators.required]],
      pagoConfirmado: [false],
      solicitudesEspeciales: [''],
    });

    const payload = data && typeof data === 'object' && 'room' in data && 'guest' in data
      ? (data as ReservationCreateDialogData)
      : null;

    if (payload?.room && payload?.guest) {
      this.lockGuestAndRoom = true;
      this.rooms = [payload.room];
      this.users = [{
        idUser: payload.guest.id,
        correo: payload.guest.email,
        nombreCompleto: payload.guest.nombreCompleto,
        rol: 1,
      }];
      this.form.patchValue({
        idHabitacion: payload.room.idHabitacion,
        idHuesped: payload.guest.id,
      });
      this.form.get('idHabitacion')?.disable();
      this.form.get('idHuesped')?.disable();
    } else {
      this.initSelects();
    }
  }

  private initSelects(): void {
    // Cargamos ambos selects al abrir el modal.
    this.roomsService.getRooms().subscribe({
      next: (rooms) => {
        this.rooms = rooms;
      },
      error: () => {
        // Si falla, se verá vacío y la API regresará error al crear.
      },
    });

    this.usersService.getUsers().subscribe({
      next: (users) => {
        // Invitado = huésped (por seguridad convertimos a number).
        this.users = users.filter((u) => Number(u.rol) === 1);
      },
      error: () => {
        this.users = [];
      },
    });
  }

  onCancel(): void {
    this.dialogRef.close(false);
  }

  private startOfDay(d: Date): Date {
    const x = new Date(d);
    x.setHours(0, 0, 0, 0);
    return x;
  }

  private endOfDay(d: Date): Date {
    const x = new Date(d);
    x.setHours(23, 59, 59, 999);
    return x;
  }

  onSubmit(): void {
    this.errorMessage = '';
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    const raw = this.form.value as any;

    // Payload con nombres en camelCase (por namingPolicy del backend).
    const payload = {
      idReservacion: raw.idReservacion?.trim() || undefined,
      idHabitacion: raw.idHabitacion,
      idHuesped: raw.idHuesped,
      fechaEntrada: this.startOfDay(new Date(raw.fechaEntrada)).toISOString(),
      fechaSalida: this.endOfDay(new Date(raw.fechaSalida)).toISOString(),
      estado: Number(raw.estado),
      numeroHuespedes: Number(raw.numeroHuespedes),
      montoTotal: Number(raw.montoTotal),
      moneda: raw.moneda,
      pagoConfirmado: Boolean(raw.pagoConfirmado),
      solicitudesEspeciales: raw.solicitudesEspeciales || undefined,
    };

    this.loading = true;
    this.reservationsService.createReservation(payload).subscribe({
      next: (res) => {
        this.loading = false;
        this.dialogRef.close(res);
      },
      error: (err) => {
        this.loading = false;
        this.errorMessage =
          err?.error?.message ?? err?.message ?? 'No se pudo crear la reservación.';
      },
    });
  }
}

<h2 mat-dialog-title>
  <mat-icon>event</mat-icon>
  Crear reservación
</h2>

<mat-dialog-content class="dialog-content">
  <form [formGroup]="form" (ngSubmit)="onSubmit()">
    <div class="grid-2">
      <mat-form-field appearance="outline" class="full-width">
        <mat-label>Habitación</mat-label>
        <mat-select formControlName="idHabitacion">
          <mat-option *ngFor="let r of rooms" [value]="r.idHabitacion">
            {{ r.numeroHabitacion }} ({{ r.tipoHabitacion }})
          </mat-option>
        </mat-select>
        <mat-error *ngIf="form.get('idHabitacion')?.hasError('required')">
          Selecciona una habitación.
        </mat-error>
      </mat-form-field>

      <mat-form-field appearance="outline" class="full-width">
        <mat-label>Huésped</mat-label>
        <mat-select formControlName="idHuesped">
          <mat-option *ngFor="let u of users" [value]="u.idUser">
            {{ u.nombreCompleto }} ({{ u.correo }})
          </mat-option>
        </mat-select>
        <mat-error *ngIf="form.get('idHuesped')?.hasError('required')">
          Selecciona un huésped.
        </mat-error>
      </mat-form-field>
    </div>

    <div class="grid-2">
      <mat-form-field appearance="outline" class="full-width">
        <mat-label>Fecha entrada</mat-label>
        <input matInput [matDatepicker]="pickerEntrada" formControlName="fechaEntrada" />
        <mat-datepicker-toggle matSuffix [for]="pickerEntrada"></mat-datepicker-toggle>
        <mat-datepicker #pickerEntrada></mat-datepicker>
        <mat-error *ngIf="form.get('fechaEntrada')?.hasError('required')">
          Requerido.
        </mat-error>
      </mat-form-field>

      <mat-form-field appearance="outline" class="full-width">
        <mat-label>Fecha salida</mat-label>
        <input matInput [matDatepicker]="pickerSalida" formControlName="fechaSalida" />
        <mat-datepicker-toggle matSuffix [for]="pickerSalida"></mat-datepicker-toggle>
        <mat-datepicker #pickerSalida></mat-datepicker>
        <mat-error *ngIf="form.get('fechaSalida')?.hasError('required')">
          Requerido.
        </mat-error>
      </mat-form-field>
    </div>

    <div class="grid-2">
      <mat-form-field appearance="outline" class="full-width">
        <mat-label>Estado</mat-label>
        <mat-select formControlName="estado">
          @for (e of estados; track e.value) {
            <mat-option [value]="e.value">{{ e.label }}</mat-option>
          }
        </mat-select>
      </mat-form-field>

      <mat-form-field appearance="outline" class="full-width">
        <mat-label>Número de huéspedes</mat-label>
        <input matInput type="number" formControlName="numeroHuespedes" />
      </mat-form-field>
    </div>

    <div class="grid-2">
      <mat-form-field appearance="outline" class="full-width">
        <mat-label>Monto total</mat-label>
        <input matInput type="number" formControlName="montoTotal" />
      </mat-form-field>

      <mat-form-field appearance="outline" class="full-width">
        <mat-label>Moneda</mat-label>
        <input matInput formControlName="moneda" />
      </mat-form-field>
    </div>

    <mat-checkbox formControlName="pagoConfirmado">Pago confirmado</mat-checkbox>

    <mat-form-field appearance="outline" class="full-width">
      <mat-label>Solicitudes especiales</mat-label>
      <input matInput formControlName="solicitudesEspeciales" placeholder="Ej: cama extra, alergias..." />
    </mat-form-field>

    <p class="error-msg" *ngIf="errorMessage">{{ errorMessage }}</p>

    <div class="actions">
      <button mat-stroked-button type="button" (click)="onCancel()" [disabled]="loading">
        <mat-icon aria-hidden="true" class="btn-icon">close</mat-icon>
        Cancelar
      </button>
      <button mat-flat-button color="primary" type="submit" [disabled]="loading">
        <mat-spinner *ngIf="loading" diameter="18"></mat-spinner>
        <mat-icon *ngIf="!loading" aria-hidden="true" class="btn-icon">check</mat-icon>
        <span *ngIf="!loading">Crear</span>
      </button>
    </div>
  </form>
</mat-dialog-content>
